    describe('module-cache-invalidation', function () {
        it('extracts dependency keys from import and export specifiers via AST parsing', function () {
            let source = `
        import alpha from './alpha';
        export { beta } from './beta.js';
        export * from './gamma.gjs';
        const ignored = "import './not-real'";
        const ignoredTemplate = \`export * from "./also-not-real"\`;
        await import('./delta.ts');
        await import(dynamicPath);
        import "https://example.com/not-in-realm";
      `;
            let paths = new RealmPaths(new URL(testRealm));
            let deps = extractModuleDependencyKeys(source, 'dir/main.gts', testRealm, paths);
            expect([...deps].sort()).toEqual([
                moduleDependencyKey('dir/alpha'),
                moduleDependencyKey('dir/beta.js'),
                moduleDependencyKey('dir/delta.ts'),
                moduleDependencyKey('dir/gamma.gjs'),
            ].sort());
        });
    });
    describe('gjs-to-placeholder', function () {
        const examples = [
            `<template>Greetings ")]</template>`,
            '<template>${{stuff}}</template>',
            `<template>
        Hello
       </template>`,
        ];
        for (let example of examples) {
            it('round-trip gjs placeholders', async function () {
                expect(placeholderJSToGJS(gjsToPlaceholderJS(example))).toBe(example);
            });
        }
        it('preserves line numbers', function () {
            let src = `
        console.log(
          <template>
            Hi
          </template>
        );
        console.log('after');
      `;
            expect(gjsToPlaceholderJS(src).split('\n')[6]).toBe(src.split('\n')[6]);
        });
    });
